const NOISE_URI="data:image/jpeg;base64,";

const dotsNav=document.getElementById('dots');
const panelEls=[...document.querySelectorAll('.panel')];
const stickyEls=panelEls.map(p=>p.querySelector('.sticky'));
const innerEls=panelEls.map(p=>p.querySelector('.inner'));
const N=panelEls.length;

panelEls.forEach((_,i)=>{
  const d=document.createElement('a');
  if(i===0)d.classList.add('on');
  d.style.cursor='pointer';
d.addEventListener('click',()=>{
  const rect=panelEls[i].getBoundingClientRect();
  const target=window.scrollY+rect.top;   
  window.scrollTo({top:target,behavior:'smooth'});
});
  dotsNav.appendChild(d);
});
const dotEls=[...dotsNav.children];

function mulberry32(a){return function(){a|=0;a=a+0x6D2B79F5|0;let t=Math.imul(a^a>>>15,1|a);t=t+Math.imul(t^t>>>7,61|t)^t;return((t^t>>>14)>>>0)/4294967296;};}
function makeSceneCanvas(palette,seed){
  const S=1024,cv=document.createElement('canvas');cv.width=cv.height=S;const ctx=cv.getContext('2d'),rnd=mulberry32(seed);
  const g=ctx.createLinearGradient(0,0,S,S);palette.forEach((c,i)=>g.addColorStop(i/(palette.length-1),c));ctx.fillStyle=g;ctx.fillRect(0,0,S,S);
  ctx.globalCompositeOperation='screen';
  for(let i=0;i<8;i++){const col=palette[(i+seed%palette.length)%palette.length];const x=rnd()*S,y=rnd()*S,r=S*(0.3+rnd()*0.5);
    const rg=ctx.createRadialGradient(x,y,0,x,y,r);rg.addColorStop(0,col);rg.addColorStop(1,'rgba(0,0,0,0)');
    ctx.globalAlpha=0.4+rnd()*0.2;ctx.fillStyle=rg;ctx.beginPath();ctx.arc(x,y,r,0,7);ctx.fill();}
  ctx.globalAlpha=1;ctx.globalCompositeOperation='source-over';return cv;
}

const canvas=document.getElementById('gl'),gl=canvas.getContext('webgl',{antialias:true,alpha:false});

const VERT=`attribute vec2 aPos;varying vec2 vUv;void main(){vUv=aPos*0.5+0.5;gl_Position=vec4(aPos,0.0,1.0);}`;

const FRAG=`
precision highp float;
varying vec2 vUv;
uniform sampler2D tFromScene;
uniform sampler2D tToScene;
uniform sampler2D tNoise;
uniform float uProgress;
uniform vec2 uNoise1Scale;
uniform vec2 uNoise2Scale;
uniform vec2 uNoise1Offset;
uniform float uUvDistortion;
uniform float uAdditionalUvDistortion;
uniform float uChromaticAberrationStrength;
uniform float uCrossfadeSize;
uniform float uCrossfadeNoise;
uniform vec2 uResolution;
uniform float uTime;
float random(vec2 p){vec3 p3=fract(vec3(p.xyx)*443.8975);p3+=dot(p3,p3.yzx+19.19);return fract((p3.x+p3.y)*p3.z);}
vec2 barrelPincushion(vec2 uv,float strength){vec2 st=uv-0.5;float theta=atan(st.x,st.y);float radius=sqrt(dot(st,st));radius*=1.0+strength*(radius*radius);return 0.5+radius*vec2(sin(theta),cos(theta));}
void main(){
  vec2 distortedUv=barrelPincushion(vUv,3.);
  vec2 distortedUvFlipped=barrelPincushion(vUv,-0.5);
  float aspect=uResolution.x/uResolution.y;
  float smallNoise=random(vUv)*2.-1.;
  vec2 noise=texture2D(tNoise,vUv*uNoise1Scale+uNoise1Offset).rg*2.-1.;
  float noise2=texture2D(tNoise,vUv*uNoise2Scale+noise+vec2(0.,uTime*0.01)).r*2.-1.;
  distortedUvFlipped+=noise2*uUvDistortion;
  float chromaticAberration=uChromaticAberrationStrength+smallNoise*0.003;
  float topThreshold=0.3+noise2*uAdditionalUvDistortion;
  float bottomThreshold=0.;
  float fromFade=1.-smoothstep(uProgress-topThreshold,uProgress-bottomThreshold,distortedUv.y);
  fromFade+=1.-smoothstep(uProgress+bottomThreshold,uProgress+topThreshold,distortedUv.y);
  fromFade=clamp(fromFade,0.,1.);
  vec2 redOffsetFrom=mix(vUv,distortedUvFlipped,fromFade);
  vec2 greenOffsetFrom=mix(vUv,distortedUvFlipped+vec2(chromaticAberration,0.0),fromFade);
  vec2 blueOffsetFrom=mix(vUv,distortedUvFlipped-vec2(chromaticAberration,0.0),fromFade);
  float redChannel=texture2D(tFromScene,redOffsetFrom).r;
  float greenChannel=texture2D(tFromScene,greenOffsetFrom).g;
  float blueChannel=texture2D(tFromScene,blueOffsetFrom).b;
  vec4 fromScene=vec4(redChannel,greenChannel,blueChannel,1.0);
  fromScene.rgb+=fromScene.rgb*0.15*fromFade;
  float toFade=1.-smoothstep(uProgress+topThreshold,uProgress+bottomThreshold,distortedUv.y);
  toFade+=1.-smoothstep(uProgress-bottomThreshold,uProgress-topThreshold,distortedUv.y);
  toFade=clamp(toFade,0.,1.);
  vec2 redOffsetTo=mix(vUv,distortedUvFlipped,toFade);
  vec2 greenOffsetTo=mix(vUv,distortedUvFlipped+vec2(chromaticAberration,0.0),toFade);
  vec2 blueOffsetTo=mix(vUv,distortedUvFlipped-vec2(chromaticAberration,0.0),toFade);
  float redChannelTo=texture2D(tToScene,redOffsetTo).r;
  float greenChannelTo=texture2D(tToScene,greenOffsetTo).g;
  float blueChannelTo=texture2D(tToScene,blueOffsetTo).b;
  vec4 toScene=vec4(redChannelTo,greenChannelTo,blueChannelTo,1.0);
  toScene.rgb+=toScene.rgb*0.15*toFade;
  float combineFade=1.-smoothstep(uProgress-uCrossfadeSize-noise2*uCrossfadeNoise,uProgress+uCrossfadeSize+noise2*uCrossfadeNoise,distortedUv.y+noise2*0.12);
  vec4 outputColor=mix(fromScene,toScene,combineFade);
  gl_FragColor=outputColor;
}`;

function compile(t,s){const sh=gl.createShader(t);gl.shaderSource(sh,s);gl.compileShader(sh);if(!gl.getShaderParameter(sh,gl.COMPILE_STATUS))console.error(gl.getShaderInfoLog(sh));return sh;}
const prog=gl.createProgram();gl.attachShader(prog,compile(gl.VERTEX_SHADER,VERT));gl.attachShader(prog,compile(gl.FRAGMENT_SHADER,FRAG));gl.linkProgram(prog);gl.useProgram(prog);
const bq=gl.createBuffer();gl.bindBuffer(gl.ARRAY_BUFFER,bq);gl.bufferData(gl.ARRAY_BUFFER,new Float32Array([-1,-1,1,-1,-1,1,1,1]),gl.STATIC_DRAW);
const aPos=gl.getAttribLocation(prog,'aPos');gl.enableVertexAttribArray(aPos);gl.vertexAttribPointer(aPos,2,gl.FLOAT,false,0,0);

const U={};['tFromScene','tToScene','tNoise','uProgress','uNoise1Scale','uNoise2Scale','uNoise1Offset','uUvDistortion','uAdditionalUvDistortion','uChromaticAberrationStrength','uCrossfadeSize','uCrossfadeNoise','uResolution','uTime'].forEach(n=>U[n]=gl.getUniformLocation(prog,n));

gl.uniform2f(U.uNoise1Scale, 0.0167, 0.0306);
gl.uniform2f(U.uNoise2Scale, 0.1691, 0.1006);
gl.uniform2f(U.uNoise1Offset, 0.026, 0.0008);
gl.uniform1f(U.uUvDistortion, 0.02);
gl.uniform1f(U.uAdditionalUvDistortion, 0.08);
gl.uniform1f(U.uChromaticAberrationStrength, 0.003);
gl.uniform1f(U.uCrossfadeSize, 0.45);
gl.uniform1f(U.uCrossfadeNoise, 0.03);

function texFrom(img,wrapRepeat){const tx=gl.createTexture();gl.bindTexture(gl.TEXTURE_2D,tx);
  gl.pixelStorei(gl.UNPACK_FLIP_Y_WEBGL,true);
  gl.texImage2D(gl.TEXTURE_2D,0,gl.RGBA,gl.RGBA,gl.UNSIGNED_BYTE,img);
  const w=wrapRepeat?gl.REPEAT:gl.CLAMP_TO_EDGE;
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_S,w);gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_T,w);
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MIN_FILTER,gl.LINEAR);gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MAG_FILTER,gl.LINEAR);return tx;}
