const sceneImgEls = [...document.querySelectorAll('.scene-img')];

function coverCanvas(img, w, h){
  const cv = document.createElement('canvas');
  cv.width = w; cv.height = h;
  const ctx = cv.getContext('2d');
  const ir = img.naturalWidth / img.naturalHeight, cr = w / h;
  let dw, dh;
  if (ir > cr){ dh = h; dw = h * ir; } else { dw = w; dh = w / ir; }
  ctx.drawImage(img, (w-dw)/2, (h-dh)/2, dw, dh);
  return cv;
}

let sceneTex = panelEls.map(() => null);
let scenesReady = false;

function buildSceneTextures(){
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  const w = Math.round(innerWidth * dpr), h = Math.round(innerHeight * dpr);
  panelEls.forEach((_, i) => {
    const img = sceneImgEls[i % sceneImgEls.length];
    if (img) sceneTex[i] = texFrom(coverCanvas(img, w, h), false);
  });
  scenesReady = true;
}

Promise.all(sceneImgEls.map(img =>
  img.complete ? Promise.resolve()
               : new Promise(r => { img.onload = r; img.onerror = r; })
)).then(buildSceneTextures);

let noiseTex=null;
const noiseImg=new Image();noiseImg.onload=()=>{noiseTex=texFrom(noiseImg,true);};noiseImg.src=NOISE_URI;

function resize(){const dpr=Math.min(window.devicePixelRatio||1,2),w=innerWidth,h=innerHeight;canvas.width=w*dpr;canvas.height=h*dpr;canvas.style.width=w+'px';canvas.style.height=h+'px';gl.viewport(0,0,canvas.width,canvas.height);}
addEventListener('resize',resize);resize();

const reduce=matchMedia('(prefers-reduced-motion: reduce)').matches;
let curGT=0;
const PROG_MIN=-0.9,PROG_MAX=1.9; 
function getWaveState(){
  const vh = innerHeight;
  const mid = vh * 0.5;          
  const tops = panelEls.map(p => p.getBoundingClientRect().top - mid);

  for (let i = 0; i < panelEls.length - 1; i++){
    const a = tops[i];      
    const b = tops[i+1];     

    if (b > 0){
      const band = vh * 0.6;        
      let p = 1 - (b / band);     
      p = Math.max(0, Math.min(1, p));
      return { idxA: i, p };
    }
  }
  return { idxA: panelEls.length - 2, p: 1 };
}

const start=performance.now();
function frame(now){
  const t=(now-start)/1000;
  const ws=getWaveState();
  const idxA=ws.idxA,idxB=idxA+1;
  const ep=PROG_MIN+ws.p*(PROG_MAX-PROG_MIN);
  curGT=idxA+ws.p;

  if(noiseTex){
    gl.useProgram(prog);
    gl.activeTexture(gl.TEXTURE0);gl.bindTexture(gl.TEXTURE_2D,sceneTex[idxA]);gl.uniform1i(U.tFromScene,0);
    gl.activeTexture(gl.TEXTURE1);gl.bindTexture(gl.TEXTURE_2D,sceneTex[idxB]);gl.uniform1i(U.tToScene,1);
    gl.activeTexture(gl.TEXTURE2);gl.bindTexture(gl.TEXTURE_2D,noiseTex);gl.uniform1i(U.tNoise,2);
    gl.uniform1f(U.uProgress,ep);gl.uniform1f(U.uTime,t);gl.uniform2f(U.uResolution,canvas.width,canvas.height);
    gl.drawArrays(gl.TRIANGLE_STRIP,0,4);
  }
  for(let i=0;i<innerEls.length;i++){const dd=Math.abs(curGT-i);innerEls[i].style.opacity=Math.max(0,1-dd).toFixed(3);}
  dotEls.forEach((d,i)=>d.classList.toggle('on',i===Math.round(curGT)));
  requestAnimationFrame(frame);
}
requestAnimationFrame(frame);